CREATE TABLE extraction_runs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), entry_id uuid NOT NULL REFERENCES journal_entries(id), attempt int NOT NULL, provider text NOT NULL, model text NOT NULL, prompt_version text NOT NULL, schema_version text NOT NULL, context_fingerprint text NOT NULL, status text NOT NULL CHECK (status IN ('running','succeeded','retryable_failed','terminal_failed')), validated_result jsonb, raw_response_ciphertext bytea, latency_ms int, input_tokens int, output_tokens int, error_code text, started_at timestamptz NOT NULL DEFAULT now(), finished_at timestamptz, UNIQUE(entry_id, attempt));
CREATE TABLE event_batches (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL REFERENCES users(id), entry_id uuid NOT NULL REFERENCES journal_entries(id), extraction_run_id uuid REFERENCES extraction_runs(id), status text NOT NULL DEFAULT 'pending' CHECK (status IN ('pending','confirmed','rejected','superseded')), version int NOT NULL DEFAULT 1, confirmed_at timestamptz, rejected_at timestamptz, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE health_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL REFERENCES users(id), batch_id uuid NOT NULL REFERENCES event_batches(id), entry_id uuid NOT NULL REFERENCES journal_entries(id), kind text NOT NULL CHECK (kind IN ('pain_observation','medication_intake','wellbeing','activity','sleep','food_drink','measurement','note')), occurred_at timestamptz NOT NULL, ended_at timestamptz, time_precision text NOT NULL CHECK (time_precision IN ('exact','approximate','date_only','inferred_from_message')), confidence numeric(4,3), status text NOT NULL DEFAULT 'pending' CHECK (status IN ('pending','confirmed','superseded','deleted')), client_ref text NOT NULL, attributes jsonb NOT NULL DEFAULT '{}'::jsonb, revision int NOT NULL DEFAULT 1, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), deleted_at timestamptz, CHECK (ended_at IS NULL OR ended_at >= occurred_at), CHECK (confidence IS NULL OR confidence BETWEEN 0 AND 1), UNIQUE(batch_id, client_ref));
CREATE INDEX health_events_confirmed_idx ON health_events(user_id, occurred_at DESC) WHERE status = 'confirmed' AND deleted_at IS NULL;
CREATE INDEX health_events_kind_idx ON health_events(user_id, kind, occurred_at DESC);
CREATE TABLE event_revisions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), event_id uuid NOT NULL REFERENCES health_events(id), revision int NOT NULL, changed_by text NOT NULL CHECK (changed_by IN ('bot_correction','web_user','reprocess','system')), before_data jsonb NOT NULL, after_data jsonb NOT NULL, reason text, created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(event_id, revision));
CREATE TABLE symptom_episodes (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL REFERENCES users(id), symptom_type text NOT NULL DEFAULT 'headache', started_at timestamptz NOT NULL, ended_at timestamptz, start_precision text NOT NULL, end_precision text, status text NOT NULL DEFAULT 'open' CHECK (status IN ('open','closed','cancelled')), max_intensity smallint CHECK (max_intensity BETWEEN 0 AND 10), created_from_event_id uuid REFERENCES health_events(id), created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), CHECK (ended_at IS NULL OR ended_at >= started_at));
CREATE INDEX symptom_episodes_open_idx ON symptom_episodes(user_id) WHERE status = 'open';
CREATE TABLE pain_observations (event_id uuid PRIMARY KEY REFERENCES health_events(id) ON DELETE CASCADE, episode_id uuid REFERENCES symptom_episodes(id), phase text NOT NULL CHECK (phase IN ('start','update','end')), intensity smallint CHECK (intensity BETWEEN 0 AND 10), locations text[] NOT NULL DEFAULT '{}', laterality text CHECK (laterality IN ('left','right','bilateral','center','unknown')), qualities text[] NOT NULL DEFAULT '{}', associated_symptoms text[] NOT NULL DEFAULT '{}', functional_impact smallint CHECK (functional_impact BETWEEN 0 AND 3), reported_relief boolean);
CREATE TABLE medication_intakes (event_id uuid PRIMARY KEY REFERENCES health_events(id) ON DELETE CASCADE, episode_id uuid REFERENCES symptom_episodes(id), medication_name_ciphertext bytea NOT NULL, medication_name_normalized text, medication_class text, dose_value numeric, dose_unit text, route text, reason text, effect_rating smallint CHECK (effect_rating BETWEEN -2 AND 2), effect_observed_at timestamptz, side_effects text[] NOT NULL DEFAULT '{}', CHECK (dose_value IS NULL OR dose_value > 0));
CREATE TABLE activities (event_id uuid PRIMARY KEY REFERENCES health_events(id) ON DELETE CASCADE, activity_type text NOT NULL, duration_minutes int CHECK (duration_minutes > 0), intensity text CHECK (intensity IN ('low','moderate','high')), distance_meters int CHECK (distance_meters > 0));
CREATE TABLE daily_checkins (event_id uuid PRIMARY KEY REFERENCES health_events(id) ON DELETE CASCADE, wellbeing_score smallint CHECK (wellbeing_score BETWEEN 0 AND 10), energy_score smallint CHECK (energy_score BETWEEN 0 AND 10), mood_score smallint CHECK (mood_score BETWEEN 0 AND 10), stress_score smallint CHECK (stress_score BETWEEN 0 AND 10), sleep_quality smallint CHECK (sleep_quality BETWEEN 0 AND 10), explicit_no_headache boolean);
CREATE TABLE sleep_records (event_id uuid PRIMARY KEY REFERENCES health_events(id) ON DELETE CASCADE, sleep_started_at timestamptz, sleep_ended_at timestamptz, duration_minutes int CHECK (duration_minutes > 0), quality_score smallint CHECK (quality_score BETWEEN 0 AND 10), interruptions int CHECK (interruptions >= 0), CHECK (sleep_ended_at IS NULL OR sleep_started_at IS NULL OR sleep_ended_at >= sleep_started_at));
CREATE TABLE food_drink_records (event_id uuid PRIMARY KEY REFERENCES health_events(id) ON DELETE CASCADE, category text NOT NULL CHECK (category IN ('meal','water','caffeine','alcohol','other')), quantity_value numeric, quantity_unit text, labels text[] NOT NULL DEFAULT '{}');
CREATE TABLE measurements (event_id uuid PRIMARY KEY REFERENCES health_events(id) ON DELETE CASCADE, measurement_type text NOT NULL CHECK (measurement_type IN ('blood_pressure','heart_rate','temperature','weight','other')), value_primary numeric NOT NULL, value_secondary numeric, unit text NOT NULL);
